Response.Content:
{
	"jsonrpc": "2.0",
	"id": "uebridge-tools-list",
	"result":
	{
		"tools": [
			{
				"name": "query-blueprint-summary",
				"description": "Return a compact Blueprint summary with counts for graphs, functions, variables, and components.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"asset_path":
						{
							"type": "string",
							"description": "Blueprint asset path"
						},
						"include_names":
						{
							"type": "boolean",
							"description": "Include function, variable, and component names"
						}
					},
					"required": [
						"asset_path"
					]
				},
				"metadata":
				{
					"kind": "query",
					"resource_scope": "blueprint",
					"mutates": false,
					"supports_batch": false,
					"supports_dry_run": false,
					"supports_compile": false,
					"supports_save": false
				}
			},
			{
				"name": "query-blueprint-graph-summary",
				"description": "Return compact graph summaries for a Blueprint, with optional sample node handles.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"asset_path":
						{
							"type": "string",
							"description": "Blueprint asset path"
						},
						"graph_name":
						{
							"type": "string",
							"description": "Optional graph name filter"
						},
						"graph_type":
						{
							"type": "string",
							"description": "Optional graph type filter"
						},
						"include_sample_nodes":
						{
							"type": "boolean",
							"description": "Include a small sample of node handles"
						},
						"max_sample_nodes":
						{
							"type": "integer",
							"description": "Maximum sample nodes per graph"
						}
					},
					"required": [
						"asset_path"
					]
				},
				"metadata":
				{
					"kind": "query",
					"resource_scope": "blueprint_graph",
					"mutates": false,
					"supports_batch": false,
					"supports_dry_run": false,
					"supports_compile": false,
					"supports_save": false
				}
			},
			{
				"name": "query-blueprint-node",
				"description": "Return detailed information for a specific Blueprint node, including object/class pin defaults.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"asset_path":
						{
							"type": "string",
							"description": "Blueprint asset path"
						},
						"node_guid":
						{
							"type": "string",
							"description": "Blueprint node GUID"
						},
						"node_handle":
						{
							"type": "object",
							"description": "Node handle returned by query-blueprint-graph-summary"
						},
						"include_pins":
						{
							"type": "boolean",
							"description": "Include pin information"
						},
						"include_connections":
						{
							"type": "boolean",
							"description": "Include pin connections"
						},
						"include_defaults":
						{
							"type": "boolean",
							"description": "Include pin defaults"
						},
						"include_position":
						{
							"type": "boolean",
							"description": "Include node position"
						}
					}
				},
				"metadata":
				{
					"kind": "detail",
					"resource_scope": "blueprint_node",
					"mutates": false,
					"supports_batch": false,
					"supports_dry_run": false,
					"supports_compile": false,
					"supports_save": false
				}
			},
			{
				"name": "query-animation-asset-summary",
				"description": "Return compact animation asset summaries for AnimSequence, AnimMontage, BlendSpace, and AnimBlueprint assets.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"asset_path":
						{
							"type": "string",
							"description": "Animation asset path"
						}
					},
					"required": [
						"asset_path"
					]
				},
				"metadata":
				{
					"kind": "query",
					"resource_scope": "generic",
					"mutates": false,
					"supports_batch": false,
					"supports_dry_run": false,
					"supports_compile": false,
					"supports_save": false
				}
			},
			{
				"name": "query-level-summary",
				"description": "Return a compact list of actors in the current level or world, with optional filtering.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"world":
						{
							"type": "string",
							"description": "Target world",
							"enum": [
								"editor",
								"pie",
								"auto"
							]
						},
						"class_filter":
						{
							"type": "string",
							"description": "Optional actor class filter"
						},
						"folder_filter":
						{
							"type": "string",
							"description": "Optional World Outliner folder filter"
						},
						"tag_filter":
						{
							"type": "string",
							"description": "Optional actor tag filter"
						},
						"include_hidden":
						{
							"type": "boolean",
							"description": "Include hidden actors"
						},
						"include_transform":
						{
							"type": "boolean",
							"description": "Include actor transforms"
						},
						"limit":
						{
							"type": "integer",
							"description": "Maximum actors to return"
						}
					}
				},
				"metadata":
				{
					"kind": "query",
					"resource_scope": "level",
					"mutates": false,
					"supports_batch": false,
					"supports_dry_run": false,
					"supports_compile": false,
					"supports_save": false
				}
			},
			{
				"name": "query-actor-detail",
				"description": "Return detailed reflected information for a specific actor in the editor or PIE world.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"world":
						{
							"type": "string",
							"description": "Target world",
							"enum": [
								"editor",
								"pie",
								"auto"
							]
						},
						"actor_name":
						{
							"type": "string",
							"description": "Actor name or label"
						},
						"actor_handle":
						{
							"type": "object",
							"description": "Actor handle returned by query-level-summary"
						},
						"include_components":
						{
							"type": "boolean",
							"description": "Include components"
						},
						"include_properties":
						{
							"type": "boolean",
							"description": "Include reflected properties"
						},
						"include_inherited":
						{
							"type": "boolean",
							"description": "Include inherited properties"
						},
						"include":
						{
							"type": "array",
							"description": "Optional detail sections: metadata, hierarchy, tags, visibility, mobility, bounds, components, properties",
							"items":
							{
								"type": "string"
							}
						}
					}
				},
				"metadata":
				{
					"kind": "detail",
					"resource_scope": "actor",
					"mutates": false,
					"supports_batch": false,
					"supports_dry_run": false,
					"supports_compile": false,
					"supports_save": false
				}
			},
			{
				"name": "query-actor-selection",
				"description": "Return the current actor selection for the resolved world, with optional transform and bounds data.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"world":
						{
							"type": "string",
							"description": "Target world",
							"enum": [
								"editor",
								"pie",
								"auto"
							]
						},
						"include_transform":
						{
							"type": "boolean",
							"description": "Include actor transforms in selection results"
						},
						"include_bounds":
						{
							"type": "boolean",
							"description": "Include actor bounds in selection results"
						},
						"limit":
						{
							"type": "integer",
							"description": "Maximum selected actors to return"
						}
					}
				},
				"metadata":
				{
					"kind": "query",
					"resource_scope": "actor",
					"mutates": false,
					"supports_batch": false,
					"supports_dry_run": false,
					"supports_compile": false,
					"supports_save": false
				}
			},
			{
				"name": "query-spatial-context",
				"description": "Return spatial context for a set of actors, including bounds, aggregate bounds, pairwise distances, and optional ground hits.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"world":
						{
							"type": "string",
							"description": "Target world",
							"enum": [
								"editor",
								"pie",
								"auto"
							]
						},
						"actors":
						{
							"type": "array",
							"description": "Actor references",
							"items":
							{
								"type": "object",
								"description": "Actor reference using either actor_name or actor_handle",
								"properties":
								{
									"actor_name":
									{
										"type": "string",
										"description": "Actor name or label"
									},
									"actor_handle":
									{
										"type": "object",
										"description": "Actor handle returned by query-level-summary or query-actor-selection"
									}
								},
								"additionalProperties": false
							}
						},
						"include_pairwise_distances":
						{
							"type": "boolean",
							"description": "Include pairwise center distances"
						},
						"include_ground_hits":
						{
							"type": "boolean",
							"description": "Include ground-hit traces below each actor"
						},
						"trace_distance":
						{
							"type": "number",
							"description": "Ground trace distance in world units"
						}
					},
					"required": [
						"actors"
					]
				},
				"metadata":
				{
					"kind": "detail",
					"resource_scope": "level",
					"mutates": false,
					"supports_batch": false,
					"supports_dry_run": false,
					"supports_compile": false,
					"supports_save": false
				}
			},
			{
				"name": "query-world-summary",
				"description": "Return high-level world state, including actor counts, loaded levels, and current selection.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"world":
						{
							"type": "string",
							"description": "Target world",
							"enum": [
								"editor",
								"pie",
								"auto"
							]
						},
						"include_levels":
						{
							"type": "boolean",
							"description": "Include loaded level list"
						},
						"include_selection":
						{
							"type": "boolean",
							"description": "Include current editor selection"
						}
					}
				},
				"metadata":
				{
					"kind": "query",
					"resource_scope": "world",
					"mutates": false,
					"supports_batch": false,
					"supports_dry_run": false,
					"supports_compile": false,
					"supports_save": false
				}
			},
			{
				"name": "query-material-summary",
				"description": "Return compact material parameter summaries with optional value expansion, true parameter filtering, and optional graph overview for base materials.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"asset_path":
						{
							"type": "string",
							"description": "Material or material instance asset path"
						},
						"parameter_names":
						{
							"type": "array",
							"description": "Optional explicit parameter names",
							"items":
							{
								"type": "string"
							}
						},
						"include_values":
						{
							"type": "boolean",
							"description": "Include current parameter values"
						},
						"include_graph_overview":
						{
							"type": "boolean",
							"description": "Include compact expression graph overview for UMaterial assets"
						}
					},
					"required": [
						"asset_path"
					]
				},
				"metadata":
				{
					"kind": "query",
					"resource_scope": "material",
					"mutates": false,
					"supports_batch": false,
					"supports_dry_run": false,
					"supports_compile": false,
					"supports_save": false
				}
			},
			{
				"name": "query-material-instance",
				"description": "Return material instance parent info and explicit parameter overrides.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"asset_path":
						{
							"type": "string",
							"description": "Material instance asset path"
						}
					},
					"required": [
						"asset_path"
					]
				},
				"metadata":
				{
					"kind": "detail",
					"resource_scope": "material_instance",
					"mutates": false,
					"supports_batch": false,
					"supports_dry_run": false,
					"supports_compile": false,
					"supports_save": false
				}
			},
			{
				"name": "query-static-mesh-summary",
				"description": "Return compact static mesh summaries including bounds, material slots, LOD settings, Nanite state, and per-LOD triangle counts.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"asset_path":
						{
							"type": "string",
							"description": "Static mesh asset path"
						}
					},
					"required": [
						"asset_path"
					]
				},
				"metadata":
				{
					"kind": "query",
					"resource_scope": "static_mesh",
					"mutates": false,
					"supports_batch": false,
					"supports_dry_run": false,
					"supports_compile": false,
					"supports_save": false
				}
			},
			{
				"name": "query-environment-summary",
				"description": "Summarize editor environment lighting actors including directional lights, sky lights, sky atmosphere, exponential height fog, and post process volumes.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"world":
						{
							"type": "string",
							"description": "Target world",
							"enum": [
								"editor",
								"pie",
								"auto"
							]
						}
					}
				},
				"metadata":
				{
					"kind": "query",
					"resource_scope": "environment",
					"mutates": false,
					"supports_batch": false,
					"supports_dry_run": false,
					"supports_compile": false,
					"supports_save": false
				}
			},
			{
				"name": "query-navigation-state",
				"description": "Query navigation system state for the target world, including registered nav data and bounds volumes.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"world":
						{
							"type": "string",
							"description": "Target world",
							"enum": [
								"editor",
								"pie",
								"auto"
							]
						},
						"include_bounds":
						{
							"type": "boolean",
							"description": "Include bounds for nav data and bounds volumes"
						}
					}
				},
				"metadata":
				{
					"kind": "query",
					"resource_scope": "generic",
					"mutates": false,
					"supports_batch": false,
					"supports_dry_run": false,
					"supports_compile": false,
					"supports_save": false
				}
			},
			{
				"name": "query-replication-summary",
				"description": "Query Blueprint replication settings for class defaults and authored member variables.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"asset_path":
						{
							"type": "string",
							"description": "Blueprint asset path"
						}
					},
					"required": [
						"asset_path"
					]
				},
				"metadata":
				{
					"kind": "query",
					"resource_scope": "generic",
					"mutates": false,
					"supports_batch": false,
					"supports_dry_run": false,
					"supports_compile": false,
					"supports_save": false
				}
			},
			{
				"name": "get-project-info",
				"description": "Get project and plugin information including project name, path, and plugin version. Optionally include project settings (input mappings, collision, gameplay tags, maps).",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"section":
						{
							"type": "string",
							"description": "Include settings section: 'input', 'collision', 'tags', 'maps', or 'all'. Omit for basic info only."
						}
					}
				},
				"metadata":
				{
					"kind": "query",
					"resource_scope": "generic",
					"mutates": false,
					"supports_batch": false,
					"supports_dry_run": false,
					"supports_compile": false,
					"supports_save": false
				}
			},
			{
				"name": "query-asset",
				"description": "Query assets: search by pattern/class/path, or inspect a specific asset. Use 'query' for search mode, 'asset_path' for inspect mode.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"query":
						{
							"type": "string",
							"description": "Search query (asset name pattern, supports * and ? wildcards). Triggers search mode."
						},
						"class":
						{
							"type": "string",
							"description": "Filter by asset class (e.g., Blueprint, StaticMesh, Material)"
						},
						"path":
						{
							"type": "string",
							"description": "Filter by path prefix (e.g., /Game/Blueprints)"
						},
						"limit":
						{
							"type": "integer",
							"description": "Maximum results for search (default: 100)"
						},
						"asset_path":
						{
							"type": "string",
							"description": "Asset path to inspect (e.g., /Game/Data/DT_Items). Triggers inspect mode."
						},
						"depth":
						{
							"type": "integer",
							"description": "Recursion depth for nested objects (default: 2, max: 5). For inspect mode."
						},
						"include_defaults":
						{
							"type": "boolean",
							"description": "Include properties with default/empty values (default: false)"
						},
						"property_filter":
						{
							"type": "string",
							"description": "Filter properties by name (wildcards supported)"
						},
						"category_filter":
						{
							"type": "string",
							"description": "Filter by UPROPERTY category"
						},
						"row_filter":
						{
							"type": "string",
							"description": "Filter DataTable rows by name (wildcards supported)"
						}
					}
				},
				"metadata":
				{
					"kind": "query",
					"resource_scope": "generic",
					"mutates": false,
					"supports_batch": false,
					"supports_dry_run": false,
					"supports_compile": false,
					"supports_save": false
				}
			},
			{
				"name": "query-datatable",
				"description": "Query a DataTable with structured schema and row fields.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"asset_path":
						{
							"type": "string",
							"description": "DataTable asset path"
						},
						"row_filter":
						{
							"type": "string",
							"description": "Optional wildcard row-name filter"
						},
						"include_schema":
						{
							"type": "boolean",
							"description": "Include reflected row schema columns"
						},
						"include_rows":
						{
							"type": "boolean",
							"description": "Include structured row data"
						}
					},
					"required": [
						"asset_path"
					]
				},
				"metadata":
				{
					"kind": "query",
					"resource_scope": "datatable",
					"mutates": false,
					"supports_batch": false,
					"supports_dry_run": false,
					"supports_compile": false,
					"supports_save": false
				}
			},
			{
				"name": "get-asset-diff",
				"description": "Get structured diff for binary Unreal assets (Blueprints, Materials, DataTables) against SCM base version. Returns JSON diff showing added/removed/modified elements. Supports Git and Perforce.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"asset_path":
						{
							"type": "string",
							"description": "Asset path (e.g., /Game/Blueprints/BP_Player) or absolute file path to the .uasset"
						},
						"scm_type":
						{
							"type": "string",
							"description": "SCM type: 'git', 'perforce', or 'auto' (auto-detect). Default: 'auto'",
							"enum": [
								"git",
								"perforce",
								"auto"
							]
						},
						"base_revision":
						{
							"type": "string",
							"description": "Base revision to compare against. Git: commit hash or 'HEAD' (default). Perforce: changelist number or '#have' (default)."
						}
					},
					"required": [
						"asset_path"
					]
				},
				"metadata":
				{
					"kind": "query",
					"resource_scope": "generic",
					"mutates": false,
					"supports_batch": false,
					"supports_dry_run": false,
					"supports_compile": false,
					"supports_save": false
				}
			},
			{
				"name": "query-unused-assets",
				"description": "Find conservative unused-asset candidates by scanning for assets with no hard or soft referencers.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"path":
						{
							"type": "string",
							"description": "Root path to scan. Defaults to /Game"
						},
						"class":
						{
							"type": "string",
							"description": "Optional asset class filter"
						},
						"limit":
						{
							"type": "integer",
							"description": "Maximum number of candidates to return"
						},
						"exclude_paths":
						{
							"type": "array",
							"description": "Additional path prefixes to exclude",
							"items":
							{
								"type": "string"
							}
						}
					}
				},
				"metadata":
				{
					"kind": "query",
					"resource_scope": "asset",
					"mutates": false,
					"supports_batch": false,
					"supports_dry_run": false,
					"supports_compile": false,
					"supports_save": false
				}
			},
			{
				"name": "get-class-hierarchy",
				"description": "Browse class inheritance tree showing parent and child classes. Supports both C++ and Blueprint classes.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"class_name":
